import React, { useMemo } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";
import { useTranslation } from "../i18n";

const BG = "#F5F5F5";
const CARD = "#FFFFFF";
const HEADER = "#E8ECE7";
const LINE = "rgba(17,24,39,0.10)";
const TEXT = "#111827";
const MUTED = "rgba(17,24,39,0.65)";
const GREEN = "#2F7D3A";
const GREEN_PILL = "#63A24E";

function Row({ icon, label, value, valueStyle }) {
  return (
    <View style={S.row}>
      <Text style={S.rowIcon}>{icon}</Text>
      <Text style={S.rowLabel}>{label}</Text>
      <Text style={[S.rowValue, valueStyle]} numberOfLines={2}>
        {value}
      </Text>
    </View>
  );
}

function Divider() {
  return <View style={S.divider} />;
}

function Card({ title, subtitle, leftIcon = "🚕", headerRight, children }) {
  return (
    <View style={S.card}>
      <View style={S.cardHeader}>
        <View style={S.headerLeft}>
          <Text style={S.headerIcon}>{leftIcon}</Text>
          <Text style={S.headerTitle}>
            {title}{" "}
            {subtitle ? <Text style={S.headerSub}>({subtitle})</Text> : null}
          </Text>
        </View>

        {headerRight ? <View style={S.headerRight}>{headerRight}</View> : null}
      </View>

      <View style={S.cardBody}>{children}</View>
    </View>
  );
}

/** ✅ NO real photo: initials avatar */
function DriverHeader({ name }) {
  const initials = (name || "")
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((s) => s[0]?.toUpperCase())
    .join("");

  return (
    <View style={S.driverHeader}>
      <View style={S.avatar}>
        <Text style={S.avatarText}>{initials || "👤"}</Text>
      </View>

      <View style={{ flex: 1 }}>
        <Row
          icon="👤"
          label=""
          value={name}
          valueStyle={{ fontWeight: "800" }}
        />
      </View>
    </View>
  );
}

export default function OfficialControlScreen() {
  const navigation = useNavigation();
  const { t } = useTranslation();

  // ✅ Demo data (replace with API later)
  const data = useMemo(
    () => ({
      plate: "CE 458-Y",
      brandModel: "Toyota Yaris (Sedan)",
      owner: "NGOUMOU Jean-Pierre",

      licenceNumber: "CUY-2026-TX-8842",
      validity: "01/01/2026 au 31/12/2026",
      zone: "Yaoundé Urbain",
      doorNumber: "1055-B",

      driverName: "FOUDA MEKONGO Christian",
      permitNumber: "04/1055/B/2018",
      category: "B",
      cni: "112455987",

      insuranceCompany: "ACTIVA Assurance",
      insuranceExpiry: "15/06/2026",
      insuranceStatus: "VALIDE",
    }),
    []
  );

  return (
    <SafeAreaView style={S.safe}>
      <ScrollView
        contentContainerStyle={S.scroll}
        showsVerticalScrollIndicator={false}
      >
        {/* Back */}
        <TouchableOpacity style={S.backBtn} onPress={() => navigation.goBack()}>
          <Text style={S.backArrow}>‹</Text>
          <Text style={S.backText}>{t("common.back")}</Text>
        </TouchableOpacity>

        {/* Authorized badge */}
        <View style={S.authorizedWrap}>
          <View style={S.authorizedPill}>
            <View style={S.dot} />
            <Text style={S.authorizedText}>{t("official.statusAuthorized")}</Text>
          </View>
        </View>

        {/* Plate big */}
        <View style={S.plateWrap}>
          <View style={S.plateBox}>
            <Text style={S.plateText}>{data.plate}</Text>
          </View>
        </View>

        {/* 1) Vehicle identification */}
        <Card
          title={t("official.vehicle.title")}
          subtitle={t("official.vehicle.subtitle")}
          leftIcon="🚕"
        >
          <Row icon="🚗" label={t("official.vehicle.plate")} value={data.plate} />
          <Divider />
          <Row
            icon="🚕"
            label={t("official.vehicle.model")}
            value={data.brandModel}
          />
          <Divider />
          <Row
            icon="📍"
            label={t("official.vehicle.owner")}
            value={data.owner}
          />
        </Card>

        {/* 2) Licence */}
        <Card
          title={t("official.licence.title")}
          subtitle={t("official.licence.subtitle")}
          leftIcon="✅"
        >
          <Row
            icon="🚗"
            label={t("official.licence.number")}
            value={data.licenceNumber}
          />
          <Divider />
          <Row
            icon="🕒"
            label={t("official.licence.validity")}
            value={data.validity}
          />
          <Divider />
